'use server'

import { auth } from "@/auth"
import { db } from "@/lib/db"
import { profiles, roadmaps, studyModules } from "@/lib/db/schema"
import { OnboardingData } from "@/lib/schemas"
import { Roadmap } from "@/lib/types"

export async function saveOnboardingData(onboardingData: OnboardingData, roadmapData: Roadmap) {
    try {
        const session = await auth()
        if (!session?.user?.id) {
            return { success: false, error: "Unauthorized" }
        }

        const userId = session.user.id

        await db.insert(profiles).values({
            userId,
            targetSkill: onboardingData.targetSkill,
            currentLevel: onboardingData.currentLevel,
            onboardingData: onboardingData,
        }).onConflictDoUpdate({
            target: profiles.userId,
            set: {
                targetSkill: onboardingData.targetSkill,
                currentLevel: onboardingData.currentLevel,
                onboardingData: onboardingData,
                updatedAt: new Date()
            }
        })

        const [insertedRoadmap] = await db.insert(roadmaps).values({
            userId,
            title: roadmapData.title,
            content: roadmapData, 
            status: "active"
        }).returning({ id: roadmaps.id })

        if (!insertedRoadmap) {
            throw new Error("Failed to create roadmap record")
        }

        const newRoadmapId = insertedRoadmap.id

        const modulesToInsert = []
        let globalModuleIndex = 0

        for (let p = 0; p < roadmapData.phases.length; p++) {
            const phase = roadmapData.phases[p]
            for (let m = 0; m < phase.modules.length; m++) {
                const module = phase.modules[m]
                modulesToInsert.push({
                    roadmapId: newRoadmapId,
                    moduleIndex: globalModuleIndex,
                    title: module.title,
                    isCompleted: false,
                })
                globalModuleIndex++
            }
        }

        if (modulesToInsert.length > 0) {
            await db.insert(studyModules).values(modulesToInsert)
        }

        return { success: true, roadmapId: newRoadmapId }

    } catch (error) {
        console.error("Error saving onboarding data:", error)
        return { success: false, error: "Internal Server Error" }
    }
}

import { inngest } from "@/lib/inngest/client";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
    try {
        const { name } = await req.json();

        const jobId = `job_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

        await inngest.send({
            name: "test/hello.world",
            data: { name, jobId },
        });

        return NextResponse.json(
            { message: "Job accepted", jobId },
            { status: 202 }
        );
    } catch (error) {
        return NextResponse.json(
            { message: "Failed to queue job" },
            { status: 500 }
        );
    }
}

"use client";

import { useState } from "react";
import { useJobStatus } from "@/hooks/useJobStatus";

export default function TestAsyncPage() {
    const [jobId, setJobId] = useState<string | null>(null);
    const { status, result, error } = useJobStatus(jobId);

    const startJob = async () => {
        setJobId(null);
        const res = await fetch("/api/test-job", {
            method: "POST",
            body: JSON.stringify({ name: "User" })
        });

        const data = await res.json();
        setJobId(data.jobId);
    };

    return (
        <div className="p-8 max-w-xl mx-auto space-y-4">
            <h1 className="text-2xl font-bold">Thử nghiệm Bất đồng bộ (Async Flow)</h1>
            <p className="text-gray-500">
                Click để gọi API. Backend sẽ lập tức trả về `HTTP 202` và `jobId`.
                Sau khoảng 3 giây, Inngest Worker chạy xong sẽ bắn Realtime event về.
            </p>

            <button
                onClick={startJob}
                className="px-4 py-2 bg-blue-600 text-white rounded-md"
                disabled={status === "pending"}
            >
                {status === "pending" ? "Đang xử lý ngầm..." : "Bắt đầu Background Task"}
            </button>

            <div className="p-4 border rounded border-gray-200 mt-4 space-y-2">
                <p><strong>Job ID:</strong> {jobId || "Chưa có"}</p>
                <p><strong>Trạng thái:</strong> {status || "Chưa có"}</p>

                {status === "completed" && (
                    <div className="bg-green-50 p-2 text-green-800 rounded">
                        <strong>Kết quả từ Worker:</strong> {result?.message}
                    </div>
                )}
            </div>
        </div>
    );
}
